import{_ as a,c as t,o,a2 as i}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1783609501000}'),n={name:"guide/installation.md"};function l(s,e,r,p,d,h){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>NueZip is available for macOS through the Mac App Store.</p><h2 id="download-options" tabindex="-1">Download Options <a class="header-anchor" href="#download-options" aria-label="Permalink to &quot;Download Options&quot;">​</a></h2><h3 id="mac-app-store-recommended" tabindex="-1">Mac App Store (Recommended) <a class="header-anchor" href="#mac-app-store-recommended" aria-label="Permalink to &quot;Mac App Store (Recommended)&quot;">​</a></h3><ul><li><strong>Download</strong>: <a href="https://apps.apple.com/app/id6785846417" target="_blank" rel="noreferrer">NueZip on the Mac App Store</a></li></ul><p>The Mac App Store version provides automatic updates and seamless integration with macOS.</p><h3 id="github-releases-alternative" tabindex="-1">GitHub Releases (Alternative) <a class="header-anchor" href="#github-releases-alternative" aria-label="Permalink to &quot;GitHub Releases (Alternative)&quot;">​</a></h3><p>If you prefer to download directly, you can get the app from <a href="https://github.com/nuezip/nuezip/releases" target="_blank" rel="noreferrer">GitHub Releases</a>. Note that this version does not receive automatic updates.</p><h2 id="installation-steps" tabindex="-1">Installation Steps <a class="header-anchor" href="#installation-steps" aria-label="Permalink to &quot;Installation Steps&quot;">​</a></h2><h3 id="mac-app-store" tabindex="-1">Mac App Store <a class="header-anchor" href="#mac-app-store" aria-label="Permalink to &quot;Mac App Store&quot;">​</a></h3><ol><li>Click the download link above or search for &quot;NueZip&quot; in the Mac App Store</li><li>Click &quot;Get&quot; to download the app</li><li>The app will automatically download and install</li><li>Launch NueZip from your Applications folder or Launchpad</li></ol><h3 id="github-releases" tabindex="-1">GitHub Releases <a class="header-anchor" href="#github-releases" aria-label="Permalink to &quot;GitHub Releases&quot;">​</a></h3><ol><li>Download the latest <code>.dmg</code> from the Releases page</li><li>Double-click the downloaded <code>.dmg</code> to open it</li><li>Drag the <code>NueZip.app</code> icon into your <code>Applications</code> folder</li><li>Eject the mounted image and open <code>NueZip</code> from <code>Applications</code></li></ol><p>If macOS prevents opening the app (Gatekeeper), open <strong>System Settings → Privacy &amp; Security</strong> and click <strong>Open Anyway</strong> for NueZip, or right-click the app and choose <strong>Open</strong>.</p><h2 id="first-launch" tabindex="-1">First Launch <a class="header-anchor" href="#first-launch" aria-label="Permalink to &quot;First Launch&quot;">​</a></h2><p>When you launch NueZip for the first time, you will be guided through an onboarding flow to:</p><ul><li><strong>Grant Folder Access</strong>: Allow NueZip to access common directories (Downloads, Documents, Desktop)</li><li><strong>Enable Finder Extension</strong>: Activate the right-click context menu for quick archive operations</li></ul><p>Grant permissions when prompted. You can modify these at any time in <strong>System Settings → Privacy &amp; Security</strong>.</p><h2 id="updates" tabindex="-1">Updates <a class="header-anchor" href="#updates" aria-label="Permalink to &quot;Updates&quot;">​</a></h2><ul><li><strong>Mac App Store version</strong>: Updates are handled automatically by the App Store</li><li><strong>GitHub Releases version</strong>: Download the newer release and replace the app in <code>Applications</code></li></ul><h2 id="uninstall" tabindex="-1">Uninstall <a class="header-anchor" href="#uninstall" aria-label="Permalink to &quot;Uninstall&quot;">​</a></h2><p>To uninstall NueZip:</p><ol><li>Quit NueZip</li><li>Drag <code>NueZip.app</code> from <code>Applications</code> to the Trash</li><li>(Optional) Remove app data and logs:</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Containers/com.w3cub.nuezip</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/Library/Logs/nuezip</span></span></code></pre></div><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>macOS</strong>: Sonoma (14) or later recommended</li><li><strong>CPU</strong>: Apple Silicon (M-series) or Intel (64-bit)</li><li><strong>Memory</strong>: 4GB minimum, 8GB recommended</li><li><strong>Storage</strong>: ~50 MB</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p>If you encounter issues during installation:</p><ul><li><strong>macOS blocks the app</strong>: Open <strong>System Settings → Privacy &amp; Security</strong> and click <strong>Open Anyway</strong> for NueZip</li><li><strong>Notarization warning</strong>: Download a signed/notarized build from the Mac App Store</li></ul><p>For more help, visit the <a href="./troubleshooting.html">Troubleshooting guide</a>.</p>`,30)])])}const m=a(n,[["render",l]]);export{u as __pageData,m as default};
